  CONSTRAINT `locations_mandal_district_id_33ed742f_fk_locations_district_id` FOREIGN KEY (`district_id`) REFERENCES `locations_district` (`id`),
  CONSTRAINT `locations_mandal_chk_1` CHECK ((`display_order` >= 0))
